// frontend/src/FlowCanvas.jsx
import React from "react";
import ReactFlow, { Background, Controls, MiniMap } from "reactflow";
import "reactflow/dist/style.css";
import { nodeTypes } from "./nodes/registryNode";
import { submitPipeline } from "./submit";

// 🧠 Label map for clean display names
const labelMap = {
  inputNode: "Input",
  textNode: "Text",
  llmNode: "LLM",
  outputNode: "Output",
  deleteNode: "Delete",
};

// 🆔 ID generator with readable slugs (no numbers)
const generateNodeId = (type) => {
  const random = Math.random().toString(36).substring(2, 6); // e.g., "k9xv"
  return `${type}-${random}`;
};

export default function FlowCanvas({
  nodes,
  edges,
  onNodesChange,
  onEdgesChange,
  onConnect,
  setNodes,
}) {
  const handleSubmit = () => {
    submitPipeline(nodes, edges);
  };

  const onDragOver = (event) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = "move";
  };

  const onDrop = (event) => {
    event.preventDefault();
    const reactFlowBounds = event.currentTarget.getBoundingClientRect();
    const raw = event.dataTransfer.getData("application/reactflow");
    if (!raw) return;

    let data;
    try {
      data = JSON.parse(raw);
    } catch (err) {
      console.error("Invalid drag payload", err);
      return;
    }

    const position = {
      x: event.clientX - reactFlowBounds.left,
      y: event.clientY - reactFlowBounds.top,
    };

    const newNode = {
      id: generateNodeId(data.nodeType),
      type: data.nodeType,
      position,
      data: {
        label: labelMap[data.nodeType] || data.nodeType,
        ...(data.data || {}),
      },
      className: data.className || "",
    };

    console.log("DROP PAYLOAD:", data);
    console.log("CREATING NODE:", newNode);

    setNodes((nds) => nds.concat(newNode));
  };

  return (
    <div style={{ width: "100%", height: "100%", position: "relative" }}>
      <ReactFlow
        nodes={nodes}
        edges={edges}
        nodeTypes={nodeTypes}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        onDrop={onDrop}
        onDragOver={onDragOver}
        fitView
      >
        <Background />
        <Controls />
        <MiniMap />
      </ReactFlow>

      <button
        onClick={handleSubmit}
        style={{
          position: "absolute",
          top: 20,
          right: 20,
          zIndex: 10,
          padding: "8px 16px",
          backgroundColor: "#4f46e5",
          color: "#fff",
          border: "none",
          borderRadius: "6px",
          cursor: "pointer",
          fontWeight: "600",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
        }}
      >
        Submit Pipeline
      </button>
    </div>
  );
}
